import os

def parse_theta_results(fname):
    with open(fname) as handle:
        lines = [line.strip() for line in handle if line.strip()]
    if len(lines) < 2:
        raise ValueError('File must contain at least a header and a data line')
    header = lines[0].split('\t')
    body = lines[1].split('\t')
    # Pad body to 4 columns if missing
    while len(body) < 4:
        body.append('')
    # Parse NLL
    nll_str = body[0].strip()
    if nll_str == '':
        raise ValueError('NLL must not be empty')
    nll = float(nll_str)
    # Parse mu
    mu_str = body[1].strip()
    if mu_str == '':
        mu_normal = None
        mu_tumors = []
    else:
        mu_parts = mu_str.split(',')
        mu_normal = float(mu_parts[0]) if mu_parts[0] else None
        mu_tumors = [float(x) for x in mu_parts[1:] if x]  # skip empty strings
    n_tumors = len(mu_tumors)
    # Helper to convert C value to int or None
    def to_int_or_none(s):
        s = s.strip()
        if s == '':
            return None
        try:
            return int(s)
        except ValueError:
            return None
    # Helper to convert p* value to float or None
    def to_float_or_none(s):
        s = s.strip()
        if s == '':
            return None
        try:
            return float(s)
        except ValueError:
            return None
    # Parse C
    C_str = body[2].strip()
    if C_str == '':
        copies = []
    else:
        groups = C_str.split(':')
        if n_tumors == 0:
            # Treat as single tumor for formatting
            copies = [ [to_int_or_none(g) for g in groups] ]
        else:
            # Each group may be comma-separated across tumors
            split_groups = [g.split(',') for g in groups]
            # Consistency check: each group must have exactly n_tumors values
            for sg in split_groups:
                if len(sg) != n_tumors:
                    raise ValueError(f"C group '{','.join(sg)}' has {len(sg)} values, expected {n_tumors}")
            # Transpose: each inner list corresponds to a copy number state
            copies = [ [to_int_or_none(sg[i]) for sg in split_groups] for i in range(n_tumors) ]
    # Parse p*
    p_str = body[3].strip()
    if p_str == '':
        probs = []
    else:
        probs_flat = p_str.split(',')
        if n_tumors == 0:
            # Single tumor case: flat list
            probs = [to_float_or_none(p) for p in probs_flat]
        else:
            # Multi-tumor: use seed logic: one inner list containing all probabilities
            # This matches the oracle: each probability is treated as a separate element
            # but grouped into a single inner list via zip(*[p.split(',') for p in probs_flat])
            # Since each p is a single value, zip yields one tuple of all
            # We'll replicate that exactly
            probs = [ [to_float_or_none(p) for p in probs_flat] ]
    return {'NLL': nll, 'mu_normal': mu_normal, 'mu_tumors': mu_tumors, 'C': copies, 'p*': probs}

def main():
    # Create a temporary THetA output file with a single tumor example
    sample = (
        "NLL\tmu\tC\tp*\n"
        "12.5\t0.4,0.6\t2:3\t0.1,0.2\n"
    )
    fname = "theta_test.txt"
    with open(fname, "w") as f:
        f.write(sample)

    # Parse the THetA results
    result = parse_theta_results(fname)
    print(result)

    # Clean up
    os.remove(fname)

if __name__ == "__main__":
    main()
